import 'package:flutter/material.dart';
import '../models/app_models.dart';
import '../services/api_service.dart';

class PenaltiesScreen extends StatefulWidget{final ApiService api; const PenaltiesScreen({super.key,required this.api}); @override State<PenaltiesScreen> createState()=>_PenaltiesScreenState();}
class _PenaltiesScreenState extends State<PenaltiesScreen>{List penalties=[];List<DriverRow> drivers=[];bool loading=true;@override void initState(){super.initState();load();}Future<void>load()async{final p=await widget.api.penalties();final d=await widget.api.drivers();setState((){penalties=p['penalties'];drivers=(d['drivers'] as List).map((e)=>DriverRow.fromJson(Map<String,dynamic>.from(e))).toList();loading=false;});}
 Future<void>manual()async{int? driverId=drivers.isEmpty?null:drivers.first.id;final reason=TextEditingController(text:'تأخير أو مخالفة إدارية');final percent=TextEditingController(text:'50');final duration=TextEditingController(text:'60');await showDialog(context:context,builder:(c)=>AlertDialog(title:const Text('عقوبة يدوية'),content:Column(mainAxisSize:MainAxisSize.min,children:[DropdownButtonFormField<int>(value:driverId,items:drivers.map((d)=>DropdownMenuItem(value:d.id,child:Text(d.name))).toList(),onChanged:(v)=>driverId=v),TextField(controller:reason,decoration:const InputDecoration(labelText:'السبب')),TextField(controller:percent,decoration:const InputDecoration(labelText:'نسبة الخصم')),TextField(controller:duration,decoration:const InputDecoration(labelText:'المدة بالدقائق'))]),actions:[TextButton(onPressed:()=>Navigator.pop(c),child:const Text('إلغاء')),FilledButton(onPressed:driverId==null?null:()async{await widget.api.manualPenalty({'driver_id':driverId,'reason':reason.text,'penalty_percent':double.parse(percent.text),'duration_minutes':int.parse(duration.text)});if(c.mounted)Navigator.pop(c);},child:const Text('تطبيق'))]));await load();}
 @override Widget build(BuildContext context)=>Scaffold(appBar:AppBar(title:const Text('العقوبات'),actions:[IconButton(onPressed:manual,icon:const Icon(Icons.add)),IconButton(onPressed:load,icon:const Icon(Icons.refresh))]),body:loading?const Center(child:CircularProgressIndicator()):ListView(children:penalties.map((p)=>Card(child:ListTile(title:Text('${p['driver_name']??''} - ${p['reason']}'),subtitle:Text('خصم ${p['penalty_percent']}% | ${p['starts_at']} إلى ${p['ends_at']} | الحالة ${p['status']}'),trailing:p['status']=='pending'?TextButton(onPressed:()async{await widget.api.approvePenalty(p['id']);await load();},child:const Text('موافقة')):null))).toList()));}
